// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Get_Services', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === PROVIDER_ID VALIDATION (required) ===
let provider_id;
if (input.provider_id === undefined || input.provider_id === null) {
  return ve('MISSING_FIELD', 'provider_id is required');
}
if (typeof input.provider_id === 'string') {
  const trimmed = input.provider_id.trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(trimmed)) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
  provider_id = parseInt(trimmed);
} else if (typeof input.provider_id === 'number') {
  provider_id = input.provider_id;
  if (!Number.isInteger(provider_id) || provider_id < 1) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
} else {
  return ve('INVALID_TYPE', 'provider_id must be a number or numeric string');
}

return [{ json: {
  success: true,
  provider_id,
  _validated: true
}}];

// Gate: _exit_early items skip to Format Response
// Valid items: build services query
const input = $input.first().json;

if (input._exit_early) {
  return [{ json: { ...input, services: [] } }];
}

const { provider_id } = input;

// Build query to get services for a specific provider
// JOIN services with provider_services to get only services offered by this provider
const services_query = `
  SELECT DISTINCT s.id, s.name
  FROM services s
  INNER JOIN provider_services ps ON s.id = ps.service_id
  WHERE ps.provider_id = ${provider_id}::int
  ORDER BY s.name;
`;

return [{ json: {
  ...input,
  services_query,
  provider_id
}}];

// GATE: Only process items with _validated === true
const input = $input.first().json;

if (input._exit_early) {
  return [];
}

return [{ json: input }];

// Handle DB error during services query
const e = $input.first().json;
const upstreamData = $('Build Services Query').isExecuted ? $('Build Services Query').first().json : {};
let error_code = 'DB_QUERY_ERROR';
let error_message = e.message || e.error?.message || 'Database query error';

if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database query timeout';
} else if (error_message.includes('relation') && error_message.includes('does not exist')) {
  error_code = 'TABLE_NOT_FOUND';
  error_message = 'Services table does not exist';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Get_Services', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format services response
const items = $input.all();
const upstreamData = $('Build Services Query').isExecuted ? $('Build Services Query').first().json : {};

// Map all service rows (only id and name)
const services = items.map(item => ({
  id: item.json.id,
  name: item.json.name
}));

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    services,
    total: services.length,
    provider_id: upstreamData.provider_id
  },
  _meta: {
    source: 'DB_Get_Services',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const input = $input.first().json;

// Process items that have data OR error_code set
if (input.data !== undefined || input.error_code !== undefined) {
  return [{ json: {
    success: input.success === true,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || null,
    _meta: input._meta || {
      source: 'DB_Get_Services',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

// Otherwise, pass-through item — skip it
return [];
